INSERT INTO public.interviews (id, tournament_id, sort_order, question, answer) VALUES (1, 148, 1, '1', '2');
INSERT INTO public.interviews (id, tournament_id, sort_order, question, answer) VALUES (2, 148, 2, '3', '4');
INSERT INTO public.interviews (id, tournament_id, sort_order, question, answer) VALUES (3, 148, 3, '5', '6');
