INSERT INTO public.interviews (id, tournament_id, sort_order, question, answer) VALUES (22, 236, 1, 'asdf', '1111');
INSERT INTO public.interviews (id, tournament_id, sort_order, question, answer) VALUES (23, 236, 2, '2222', '3333');
INSERT INTO public.interviews (id, tournament_id, sort_order, question, answer) VALUES (24, 236, 3, 'aaaaaaaaaaaaa', 'qwerasdfzxcv');
INSERT INTO public.interviews (id, tournament_id, sort_order, question, answer) VALUES (25, 1, 1, '大会全体を通して、ご自身の調子やツモの感触はどうでしたか？', '四人打ちにしてはいいところがよく入ったと思います。');
INSERT INTO public.interviews (id, tournament_id, sort_order, question, answer) VALUES (26, 1, 2, '大会前に密かに立てていた「テーマ」や「作戦」はありましたか？', '楽しく打てたらいいなぁって感じで特に作戦はありません。');
INSERT INTO public.interviews (id, tournament_id, sort_order, question, answer) VALUES (27, 1, 3, '今大会を通じて、ご自身の中で「MVP」と言える最高のアガリ（または最高のファインプレー）はどの局でしたか？', '決勝戦の親の時に清一色上がった時ですかね、、、配牌チートだったし思ってた所全部入って来ました、');
INSERT INTO public.interviews (id, tournament_id, sort_order, question, answer) VALUES (28, 1, 4, '逆に「あれは危なかった」、「実はあの時、手が震えていた」というヒヤッとした場面や、裏目に出た局はありましたか？', '特に無し');
INSERT INTO public.interviews (id, tournament_id, sort_order, question, answer) VALUES (29, 1, 5, '一番警戒していた、あるいは「こいつにだけは負けたくない」と思っていたプレイヤーは誰でしたか？', 'ミカさんですね！');
INSERT INTO public.interviews (id, tournament_id, sort_order, question, answer) VALUES (30, 1, 6, '今回の優勝賞品は、どのように使いたいですか？', '毎週水曜日会社にヤクルトさんくるのでそこで使います！
INSERT INTO public.interviews (id, tournament_id, sort_order, question, answer) VALUES (31, 1, 7, '他の参加者たちへ、チャンピオンから愛のあるメッセージ・アドバイスをお願いします！', '勝ち負けにこだわらず楽しく麻雀しましょう。');
INSERT INTO public.interviews (id, tournament_id, sort_order, question, answer) VALUES (32, 1, 8, '最後に、次回大会への意気込みをお願いします！', '討伐賞は誰にも渡しません！');
